import React, { useRef } from "react";
import ReactDOM from "react-dom";
import {Link,Routes, Route, Navigate, BrowserRouter} from 'react-router-dom';
import './Design.css';
import { useForm } from "react-hook-form";

const isValidEmail = email =>
  // eslint-disable-next-line no-useless-escape
  /^(([^<>()[\]\\.,;:\s@\"]+(\.[^<>()[\]\\.,;:\s@\"]+)*)|(\".+\"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/.test(
    email
  );


export default function Login () 
{
    const { register, handleSubmit,  formState: { errors } } = useForm({
        mode: "onBlur",
        defaultValues: {
          email: ""
        }
      });

      const onSubmit = () => {};

    const handleEmailValidation = email => {
        console.log("ValidateEmail was called with", email);
    
        const isValid = isValidEmail(email);
    
        const validityChanged =
          (errors.email && isValid) || (!errors.email && !isValid);
        if (validityChanged) {
          console.log("Fire tracker with", isValid ? "Valid" : "Invalid");
        }
    
        return isValid;
      };
    return (<>
    <div className="bg">
    <br></br>
    <br></br>
     <div  className="titlebar"> 
        Login
    </div>
    <div  className="form">
        <br></br>
        <br></br>
        <form onSubmit={handleSubmit(onSubmit)}>
            <input placeholder = "Email" type = "text" id = "email" name='email' ref={register({ required: true, validate: handleEmailValidation })}> </input>
            <br></br>
            <input placeholder = "Password" type = "text" id =  "password" name = "password"></input>
            <br></br>
        </form>
        <div className="center">
        <button  id = "submitButton" type='submit' value="Submit"> Submit </button>
        <br></br>
        </div>
        <br></br>
    </div>
    <p >Not a Member? <Link to = "/" className="link"> Signup</Link></p>
    <br></br>
    </div>
     
    </>)
}
